proof_block:
reveal(StrictlyOrderedVec::valid);
K::cmp_properties();
if post1_self_.valid()
    && post2_self_.valid()
    && post1_self_@.len() == pre_self_@.len() + 1
    && post2_self_@.len() == pre_self_@.len() + 1
    && (r1 as int) < post1_self_@.len()
    && (r2 as int) < post2_self_@.len()
    && post1_self_@ == pre_self_@.insert(r1 as int, k)
    && post2_self_@ == pre_self_@.insert(r2 as int, k)
    && post1_self_@.to_set() == pre_self_@.to_set().insert(k)
    && post2_self_@.to_set() == pre_self_@.to_set().insert(k)
{
    let pre_s: Seq<K> = pre_self_@;
    let p1: Seq<K> = post1_self_@;
    let p2: Seq<K> = post2_self_@;
    let i1: int = r1 as int;
    let i2: int = r2 as int;

    assert(p1 == pre_s.insert(i1, k));
    assert(p2 == pre_s.insert(i2, k));
    assert(p1.len() == pre_s.len() + 1);
    assert(p2.len() == pre_s.len() + 1);

    if i1 < i2 {
        assert(i1 + 1 < p1.len());
        assert(p1[i1] == k);
        assert(p1[i1 + 1] == pre_s[i1]);
        assert(p1[i1].cmp_spec(p1[i1 + 1]).lt());
        assert(k.cmp_spec(pre_s[i1]).lt());

        assert(p2[i1] == pre_s[i1]);
        assert(p2[i2] == k);
        assert(p2[i1].cmp_spec(p2[i2]).lt());
        assert(pre_s[i1].cmp_spec(k).lt());

        assert(pre_s[i1].cmp_spec(k).gt());
        assert(false);
    } else if i2 < i1 {
        assert(i2 + 1 < p2.len());
        assert(p2[i2] == k);
        assert(p2[i2 + 1] == pre_s[i2]);
        assert(p2[i2].cmp_spec(p2[i2 + 1]).lt());
        assert(k.cmp_spec(pre_s[i2]).lt());

        assert(p1[i2] == pre_s[i2]);
        assert(p1[i1] == k);
        assert(p1[i2].cmp_spec(p1[i1]).lt());
        assert(pre_s[i2].cmp_spec(k).lt());

        assert(pre_s[i2].cmp_spec(k).gt());
        assert(false);
    }

    assert(i1 == i2);
    assert(r1 == r2);
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);
}
